query($characterId:Int!){
  character(characterId: $characterId) {
    name
    gender
  }

  location(locationId:8) {
    id
    name
    dimension
  }
  episode(episodeId:8){
    name
  }
  characters(filters: {name : "Rahul"}) {
    info {
      count
    }
    result {
      type
      id
    }
  }
}
